    def __init__(self, dom: minidom.Element) -> None:
        self._node = dom

    def __repr__(self) -> str:
        return self.toxml()

    def __getitem__(self, key: str) -> str:
        node = self._node.getAttributeNode(key)
        if node is not None:
            return node.value
        else:
            raise KeyError(key)

